import sys

def main():
	data = sys.stdin.read().splitlines()
	n = int(data[0])
	people_data = []
	for i in range(1, n+1):
		parts = data[i].split()
		if len(parts) < 3:
			continue
		name = parts[0]
		try:
			age = int(parts[1])
			city = ' '.join(parts[2:])
		except ValueError:
			continue
		people_data.append({
			 "name": name,
			 "age": age,
			 "city": city
			})

	result = {
		"people": people_data,
	}

	print(result, end="")

if __name__ == "__main__":
	main()
